   321	    private static UserDefinedExpressionMethodMapping? TryBuildExpressionMapping(
   322	        SimpleMappingBuilderContext ctx,
   323	        IMethodSymbol methodSymbol
   324	    )
   325	    {
   326	        if (methodSymbol.IsGenericMethod)
   327	            return null;
   328	
   329	        // Only handle parameterless methods - Expression<Func<TSource, TTarget>> mappings
   330	        // are meant to be used like IQueryable projections where the source type comes from
   331	        // the Expression's type arguments, not from method parameters
   332	        if (methodSymbol.Parameters.Length > 0)
   333	            return null;
   334	
   335	        // Check if return type is Expression<Func<TSource, TTarget>>
   336	        var returnType = methodSymbol.ReturnType;
   337	        if (!returnType.ExtendsOrImplementsGeneric(ctx.Types.Get(typeof(Expression<>)), out var expressionType))
   338	            return null;
   339	
   340	        // Get the Func<TSource, TTarget> type argument
   341	        if (expressionType.TypeArguments[0] is not INamedTypeSymbol funcType)
   342	            return null;
   343	
   344	        if (!funcType.ExtendsOrImplementsGeneric(ctx.Types.Get(typeof(Func<,>)), out var funcTypeArgs))
   345	            return null;
   346	
   347	        // Extract source and target types from the Func<TSource, TTarget> type arguments.
   348	        // Unlike method parameters, type arguments do not go through SymbolAccessor.WrapMethodParameter,
   349	        // so we need to upgrade nullability explicitly.
   350	        var sourceType = ctx.SymbolAccessor.UpgradeNullable(funcTypeArgs.TypeArguments[0]);
   351	        var targetType = ctx.SymbolAccessor.UpgradeNullable(funcTypeArgs.TypeArguments[1]);
   352	
   353	        return new UserDefinedExpressionMethodMapping(methodSymbol, sourceType, targetType, ctx.SymbolAccessor.UpgradeNullable(returnType));
   354	    }
