   356	    private static NullFallbackValue? GetTypeSwitchNullArm(IMethodSymbol method, MappingMethodParameters parameters)
   357	    {
   358	        // target is always the return type for runtime target mappings
   359	        Debug.Assert(parameters.Target == null);
   360	        var targetType = method.ReturnType;
   361	        var sourceType = parameters.Source.Type;
   362	
   363	        // no polymorphism for extension methods...
   364	        // for type parameters:
   365	        // for the target type we assume a non-nullable by default
   366	        // for the source type we assume a nullable by default
   367	        var targetCanBeNull = targetType is ITypeParameterSymbol tpsTarget ? tpsTarget.IsNullable() ?? false : targetType.IsNullable();
   368	        var sourceCanBeNull = sourceType is ITypeParameterSymbol tpsSource ? tpsSource.IsNullable() ?? true : sourceType.IsNullable();
   369	        return !sourceCanBeNull ? null
   370	            : targetCanBeNull ? NullFallbackValue.Default
   371	            : NullFallbackValue.ThrowArgumentNullException;
   372	    }
