    )
    {
        if (!Method.IsGenericMethod)
            return null;

        var typeArguments = new ITypeSymbol[Method.TypeParameters.Length];
        for (var i = 0; i < Method.TypeParameters.Length; i++)
        {
            if (!inferredTypes.TryGetValue(Method.TypeParameters[i], out var typeArgument))
                return null;

            typeArguments[i] = typeArgument;
        }

        return new UserImplementedMethodMapping(
            receiver,
            Method.Construct(typeArguments),
            Default,
            sourceParameter with { Type = sourceType },
            targetType,
            referenceHandlerParameter,
            IsExternal,
            targetNullability
        );
    }

    public override ExpressionSyntax Build(TypeMappingBuildContext ctx)
    {
        var methodName = BuildMethodName();

