private T? FindGenericUserImplementedMapping(
    SimpleMappingBuilderContext ctx,
    TypeMappingKey mappingKey,
    ParameterScope? scope
)
{
    foreach (var mapping in _userMappingsByMethod.Values)
    {
        if (mapping is not UserImplementedMethodMapping { Method.IsGenericMethod: true } genericMapping)
            continue;

        var typeCheckerResult = ctx.GenericTypeChecker.InferAndCheckTypes(
            genericMapping.Method.TypeParameters,
            (genericMapping.SourceType, mappingKey.Source),
            (genericMapping.TargetType, mappingKey.Target)
        );
        if (!typeCheckerResult.Success)
            continue;

        if (
            genericMapping.TryBuildGenericMapping(mappingKey.Source, mappingKey.Target, typeCheckerResult.InferredTypes)
            is not T constructedMapping
        )
        {
            continue;
        }

        if (scope?.TryUseParameters(constructedMapping) == false)
            continue;

        _usedMappingKeys.Add(new TypeMappingKey(genericMapping));
        return constructedMapping;
    }

    return default;
}

