        {
            if (scope is { IsEmpty: false })
                return FindByParameters(mappingKey, scope);

            if (_defaultMappings.TryGetValue(mappingKey, out var mapping))
            {
                _usedMappingKeys.Add(mappingKey);
            }

            return mapping;
        }


