using Riok.Mapperly.Diagnostics;
using Riok.Mapperly.Helpers;

namespace Riok.Mapperly.Descriptors;

[DebuggerDisplay("{GetType().Name}({Source} => {Target})")]
public class MappingBuilderContext : SimpleMappingBuilderContext
{
